/**
 * Initialize Envelope (TVPX__20)
 * Bulletproof normalization for downstream multi-LLM pipeline.
 */
function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const incoming = $json || {};
const now = new Date().toISOString();

const baseCtx = (incoming.ctx && typeof incoming.ctx === 'object') ? incoming.ctx : {};
const traceSeed = JSON.stringify(incoming).slice(0, 5000) + '::' + now;

const ctx = {
  project_ns: 'TVPX',
  brand_name: 'The Velvet Paradox',
  trace_id: baseCtx.trace_id || `tvpx_${fnv1a(traceSeed)}`,
  trigger_mode: baseCtx.trigger_mode || incoming.trigger_mode || 'internal',
  route_mode: baseCtx.route_mode || incoming.route_mode || 'concept_forge',
  received_at: now,
  crawl_run_id: String(incoming.crawl_run_id || baseCtx.crawl_run_id || '').trim(),
  source_id: String(incoming.source_id || baseCtx.source_id || '').trim(),
  max_fragments_for_llm: Number(baseCtx.max_fragments_for_llm || incoming.max_fragments_for_llm || 10),
  max_chars_per_fragment_for_llm: Number(baseCtx.max_chars_per_fragment_for_llm || incoming.max_chars_per_fragment_for_llm || 1400),
  target_abstraction_min: Number(baseCtx.target_abstraction_min || incoming.target_abstraction_min || 5.8),
  target_abstraction_max: Number(baseCtx.target_abstraction_max || incoming.target_abstraction_max || 6.8)
};

const source = (incoming.source && typeof incoming.source === 'object') ? incoming.source : {};

return [{ json: { ctx, source, input: incoming.input || incoming, carry: incoming.carry || {}, provided_fragments: Array.isArray(incoming.fragments) ? incoming.fragments : [] } }];

/**
 * Pick Candidate Run
 * Selects an eligible crawl_run_id from clean fragments when no run was supplied.
 */
const base = $items('Initialize Envelope')[0]?.json || {};
const baseCtx = (base.ctx && typeof base.ctx === 'object') ? base.ctx : {};
const baseSource = (base.source && typeof base.source === 'object') ? base.source : {};
const requestedSourceId = String(baseCtx.source_id || '').trim();

const fragmentRows = $items('Get Clean Fragments')
  .map(i => i.json || {})
  .filter(r => r && Object.keys(r).length);

const conceptRows = $items('Get Existing Concepts')
  .map(i => i.json || {})
  .filter(r => r && Object.keys(r).length);

const consumedRunIds = new Set(
  conceptRows
    .map(r => String(r.crawl_run_id || '').trim())
    .filter(Boolean)
);

const groups = new Map();
for (const row of fragmentRows) {
  const fragmentId = String(row.fragment_id || row.id || row.dt_row_id || '').trim();
  const crawlRunId = String(row.crawl_run_id || '').trim();
  const sourceId = String(row.source_id || '').trim();
  const cleanedText = String(row.cleaned_text || row.text || row.raw_text || '').trim();
  const qaStatus = String(row.qa_status || '').trim().toLowerCase();
  const createdAt = String(row.created_at || '').trim();

  if (!fragmentId || !crawlRunId || !sourceId || !cleanedText) continue;
  if (qaStatus && qaStatus !== 'clean') continue;
  if (requestedSourceId && sourceId !== requestedSourceId) continue;

  if (!groups.has(crawlRunId)) {
    groups.set(crawlRunId, {
      crawl_run_id: crawlRunId,
      source_id: sourceId,
      fragments: [],
      newest_created_at: '',
    });
  }

  const group = groups.get(crawlRunId);
  if (group.fragments.some(f => String(f.fragment_id || '').trim() === fragmentId)) continue;
  group.fragments.push(row);
  if (createdAt && (!group.newest_created_at || createdAt > group.newest_created_at)) {
    group.newest_created_at = createdAt;
  }
}

const candidates = Array.from(groups.values())
  .map(group => ({
    ...group,
    fragment_count: group.fragments.length,
  }))
  .filter(group => group.fragment_count >= 3)
  .filter(group => !consumedRunIds.has(group.crawl_run_id))
  .sort((a, b) => {
    if (b.fragment_count !== a.fragment_count) return b.fragment_count - a.fragment_count;
    return String(b.newest_created_at || '').localeCompare(String(a.newest_created_at || ''));
  });

const picked = candidates[0] || null;
const nextCtx = {
  ...baseCtx,
  crawl_run_id: String(picked?.crawl_run_id || baseCtx.crawl_run_id || '').trim(),
  source_id: String(picked?.source_id || baseCtx.source_id || '').trim(),
};

return [{
  json: {
    ctx: nextCtx,
    source: baseSource,
    fragments: Array.isArray(picked?.fragments) ? picked.fragments : [],
    candidate_run: picked ? {
      crawl_run_id: picked.crawl_run_id,
      source_id: picked.source_id,
      fragment_count: picked.fragment_count,
      newest_created_at: picked.newest_created_at,
    } : null,
    candidate_debug: {
      requested_source_id: requestedSourceId,
      total_clean_fragments_scanned: fragmentRows.length,
      grouped_runs: groups.size,
      consumed_runs_count: consumedRunIds.size,
      eligible_runs_count: candidates.length,
    },
  }
}];

/**
 * Reattach Context After Fragments
 * Supports both direct crawl_run_id lookups and autonomous run selection.
 */
const base = $items('Initialize Envelope')[0]?.json || {};
let autonomous = {};
try {
  autonomous = $items('Pick Candidate Run')[0]?.json || {};
} catch {
  autonomous = {};
}

const baseCtx = (base.ctx && typeof base.ctx === 'object') ? base.ctx : {};
const autoCtx = (autonomous.ctx && typeof autonomous.ctx === 'object') ? autonomous.ctx : {};
const ctx = String(autoCtx.crawl_run_id || '').trim() ? autoCtx : baseCtx;

const inputRows = $input.all().map(i => i.json || {});
const dtFragmentRows = inputRows.filter(row => row && String(row.fragment_id || '').trim());
const autonomousFragments = Array.isArray(autonomous.fragments) ? autonomous.fragments : [];
const providedFragments = Array.isArray(base.provided_fragments) ? base.provided_fragments : [];
const fragments = dtFragmentRows.length ? dtFragmentRows : (autonomousFragments.length ? autonomousFragments : providedFragments);

const sourceLookupRow = inputRows.find(row => {
  if (!row || String(row.fragment_id || '').trim()) return false;
  return Boolean(row.source_id || row.source_url || row.url || row.source_label || row.source_type || row.crawl_profile);
});

const baseSource = (base.source && typeof base.source === 'object') ? base.source : {};
const autonomousSource = (autonomous.source && typeof autonomous.source === 'object') ? autonomous.source : {};
const source = (sourceLookupRow && Object.keys(sourceLookupRow).length)
  ? sourceLookupRow
  : (Object.keys(autonomousSource).length ? autonomousSource : baseSource);

return [{
  json: {
    ctx,
    source,
    fragments,
    candidate_run: autonomous.candidate_run || null,
    candidate_debug: autonomous.candidate_debug || null,
  }
}];

/** Build No Fragments Reject */
const base = $items('Reattach Context After Fragments')[0].json;
const ctx = base.ctx;
const now = new Date().toISOString();
return [{
  json: {
    ctx,
    reject: {
      reject_id: `tvpx_rej_${ctx.trace_id}_no_fragments`,
      trace_id: ctx.trace_id,
      stage_name: 'concept_forge_ingress',
      rejection_reason: 'No eligible fragments were found for concept forging. The selected crawl run may be empty, already consumed, or missing clean fragments.',
      raw_output_json: JSON.stringify({ crawl_run_id: ctx.crawl_run_id, source_id: ctx.source_id }),
      created_at: now
    }
  }
}];

/**
 * Assemble Fragment Bundle
 * Selects high-signal fragments aligned with The Velvet Paradox creative DNA.
 */
function clean(s) {
  return String(s || '').replace(/\r/g, '').replace(/[\t ]+/g, ' ').trim();
}
function clip(s, n) {
  const t = clean(s);
  return t.length > n ? t.slice(0, n) + '…' : t;
}
const base = $json;
const ctx = base.ctx;
const source = base.source || {};
const frags = Array.isArray(base.fragments) ? base.fragments : [];

const SIGNAL = ['pressure','fracture','collapse','repair','restraint','rupture','erosion','threshold','damage','bruise','stain','residue','seep','crack','buckle','warp','misalign','aftermath','tension','constraint','weight','drift','fragile','ritual','memory','identity','veil','shadow','fog','silence','ruin','relic','static','paradox'];
function scoreFrag(t) {
  const s = t.toLowerCase();
  let score = 0;
  for (const w of SIGNAL) if (s.includes(w)) score += 1;
  if (/(stone|plaster|velvet|metal|dust|smoke|haze|wet|rust|cloth|feather|fur|wax|candle|mirror|arch|stair)/i.test(t)) score += 3;
  if (t.length > 500) score += 1;
  return score;
}

const normalized = frags.map(f => {
  const cleaned = clean(f.cleaned_text || f.text || f.raw_text || '');
  return {
    fragment_id: String(f.fragment_id || f.id || f.dt_row_id || '').trim(),
    page_url: String(f.page_url || f.url || '').trim(),
    page_title: String(f.page_title || f.title || '').trim(),
    cleaned_text: cleaned
  };
}).filter(x => x.cleaned_text);

normalized.sort((a,b) => scoreFrag(b.cleaned_text) - scoreFrag(a.cleaned_text));

const takeN = Math.max(3, Math.min(Number(ctx.max_fragments_for_llm || 10), 16));
const maxChars = Math.max(600, Math.min(Number(ctx.max_chars_per_fragment_for_llm || 1400), 2200));

const picked = normalized.slice(0, takeN).map(x => ({
  fragment_id: x.fragment_id,
  page_url: x.page_url,
  page_title: x.page_title,
  excerpt: clip(x.cleaned_text, maxChars)
}));

const excerptBlock = picked.map((p, i) => {
  const head = `[#${i+1}] ${p.page_title || 'Untitled'} | ${p.page_url || ''}`.trim();
  return `${head}\n${p.excerpt}`;
}).join('\n\n---\n\n');

return [{
  json: {
    ctx,
    source,
    bundle: {
      source_id: ctx.source_id,
      crawl_run_id: ctx.crawl_run_id,
      fragment_ids: picked.map(p => p.fragment_id).filter(Boolean),
      excerpt_block: excerptBlock
    }
  }
}];

const base = $items('Assemble Fragment Bundle')[0]?.json;
if (!base) throw new Error('TVPX__20: missing Assemble Fragment Bundle payload.');

const rows = $input.all().map((i) => i.json || {}).filter(Boolean);

const archetypes = rows.map((r) => ({
  archetype_id: String(r.archetype_id || '').trim(),
  archetype_name: String(r.archetype_name || '').trim(),
  allowed_text_role: String(r.allowed_text_role || 'none').trim(),
  subject_mode_bias_json: String(r.subject_mode_bias_json || '[]'),
  camera_dna: String(r.camera_dna || '').trim(),
  palette_dna: String(r.palette_dna || '').trim(),
  material_dna_json: String(r.material_dna_json || '[]'),
  surreal_lift_rules_json: String(r.surreal_lift_rules_json || '[]'),
  negative_space_dna: String(r.negative_space_dna || '').trim(),
  forbidden_tells_json: String(r.forbidden_tells_json || '[]'),
  notes: String(r.notes || '').trim(),
})).filter((x) => x.archetype_id);

return [{
  json: {
    ...base,
    archetype_registry_json: JSON.stringify(archetypes, null, 2),
  },
}];

