  'paperwork',
  'article illustration',
];

const foundHardBans = hardBans.filter((term) => blob.includes(term));
const subjectMode = String(seed.subject_mode || '').trim();
const score = Number(critic.score || 0);
const brandFit = Number(critic.brand_fit || 0);
const refAlign = Number(critic.reference_alignment || 0);
const antiEditorial = Number(critic.anti_editorial || 0);

const reasons = [];
if (foundHardBans.length) reasons.push(...foundHardBans.map((term) => \`hard-ban:\${term}\`));
if (!['single_figure', 'pair', 'small_group', 'implied_absence'].includes(subjectMode)) {
  reasons.push(\`bad-subject-mode:\${subjectMode || 'missing'}\`);
}
if (subjectMode === 'implied_absence' && !/threshold|door|window|bed|chair|couch|altar|mirror|flowers|ruin|pond|field|hall/i.test(blob)) {
  reasons.push('implied-absence-too-weak');
}
if (score < 8.2) reasons.push('critic-score-low');
if (brandFit < 8.2) reasons.push('brand-fit-low');
if (refAlign < 8.2) reasons.push('reference-alignment-low');
if (antiEditorial < 8.2) reasons.push('anti-editorial-low');

return [{
  json: {
    ...j,
    gate: {
      approve: reasons.length === 0,
      reasons,
      archetype_id: archetypeId,
      found_hard_bans: foundHardBans,
    },
  },
}];

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const j = $json || {};
const ctx = j.ctx || {};
const bundle = j.bundle || {};
const seed = j.scene_seed || {};
const critic = j.image_native_critic || {};
const route = j.archetype_route || {};
const now = new Date().toISOString();

const fragmentIds = Array.isArray(bundle.fragment_ids) ? bundle.fragment_ids.filter(Boolean) : [];
if (!fragmentIds.length) {
  throw new Error('TVPX__20: scene seed cannot be written without fragment_ids.');
}

const seedHashBase = [
  ctx.trace_id,
  ctx.crawl_run_id,
  ctx.source_id,
  route.archetype_id,
  seed.scene_kernel,
  fragmentIds.join(','),
].join('::');

const sceneSeedId = \`tvpx_ss_\${fnv1a(seedHashBase)}\`;

const row = {
  scene_seed_id: sceneSeedId,
  trace_id: String(ctx.trace_id || '').trim(),
  crawl_run_id: String(ctx.crawl_run_id || '').trim(),
  origin_type: 'crawler',
  source_id: String(ctx.source_id || '').trim(),
  parent_scene_seed_id: null,
  root_scene_seed_id: sceneSeedId,
  seed_fragment_ids_json: JSON.stringify(fragmentIds),
  archetype_id: String(route.archetype_id || '').trim(),
  subject_mode: String(seed.subject_mode || '').trim(),
  scene_kernel: String(seed.scene_kernel || '').trim(),
  concept_thesis: String(seed.concept_thesis || '').trim(),
  symbolic_tension: String(seed.symbolic_tension || '').trim(),
  material_anchor: String(seed.material_anchor || '').trim(),
  spatial_directive: String(seed.spatial_directive || '').trim(),
  palette_directive: String(seed.palette_directive || '').trim(),
  texture_directive: String(seed.texture_directive || '').trim(),
  dominant_subject: String(seed.dominant_subject || '').trim(),
  setting_family: String(seed.setting_family || '').trim(),
  ceremonial_logic: String(seed.ceremonial_logic || '').trim(),
  surreal_pressure: String(seed.surreal_pressure || '').trim(),
  negative_space_note: String(seed.negative_space_note || '').trim(),
  omission_notes: String(seed.omission_notes || '').trim(),
  forbidden_excess_json: JSON.stringify(Array.isArray(seed.forbidden_excess) ? seed.forbidden_excess : []),
  render_budget_json: JSON.stringify(seed.render_budget || { max_named_props: 5, max_background_motifs: 2, max_prompt_words: 140 }),
  quality_score: Number(critic.score || 0),
  brand_fit_score: Number(critic.brand_fit || 0),
  reference_alignment_score: Number(critic.reference_alignment || 0),
  state: 'ready',
  lock_owner: '',
  lock_expires_at: null,
  used_count: 0,
  last_used_at: null,
  rejection_reason: '',
  created_at: now,
  updated_at: now,
};

return [{
  json: {
    ctx: {
      ...ctx,
      scene_seed_id: sceneSeedId,
      root_scene_seed_id: sceneSeedId,
    },
    scene_seed_row: row,
  },
}];

const j = $json || {};
const now = new Date().toISOString();
const critic = j.image_native_critic || {};
const gate = j.gate || {};

const reasons = [
  String(critic.rejection_reason || '').trim(),
  ...(Array.isArray(gate.reasons) ? gate.reasons : []),
].filter(Boolean);

return [{
  json: {
    ctx: j.ctx || {},
    reject: {
      reject_id: \`tvpx_rej_\${String(j.ctx?.trace_id || 'trace').trim()}_scene_seed_\${now.replace(/[:.]/g, '')}\`,
      trace_id: String(j.ctx?.trace_id || '').trim(),
      stage_name: 'scene_seed_gate',
      rejection_reason: reasons.join(' | ') || 'Rejected by deterministic image-native gate.',
      raw_output_json: JSON.stringify({
        gate,
        critic,
        scene_seed: j.scene_seed || {},
        archetype_route: j.archetype_route || {},
      }),
      created_at: now,
    },
  },
}];
